import{_ as E,C as d,o as r,c as i,a2 as e,E as l}from"./chunks/framework.BnBoz4Zl.js";const D=JSON.parse('{"title":"第三篇 进阶系统：把方法变成可复用工作流","description":"当一个任务能够稳定通过验收，再考虑沉淀为方法卡、Skill、多 Agent 或自动化。本篇只使用通用方法和合成样例。 一项任务完成后，值得保留的内容不只有最终文件。长期使用 WorkBuddy 时，应同时管理工作成果、协作方法和接续能力，让资产在更换人员、设备或 Agent 后仍然可用。","frontmatter":{},"headers":[],"relativePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/index.md","filePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/index.md","lastUpdated":1784770175000}'),A={name:"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/index.md"};function o(B,t,n,_,h,s){const a=d("MermaidDiagram");return r(),i("div",null,[t[0]||(t[0]=e('<h1 id="第三篇-进阶系统-把方法变成可复用工作流" tabindex="-1">第三篇 进阶系统：把方法变成可复用工作流 <a class="header-anchor" href="#第三篇-进阶系统-把方法变成可复用工作流" aria-label="Permalink to &quot;第三篇 进阶系统：把方法变成可复用工作流&quot;">​</a></h1><p>当一个任务能够稳定通过验收，再考虑沉淀为方法卡、Skill、多 Agent 或自动化。本篇只使用通用方法和合成样例。</p><h2 id="ai-协作资产全景图" tabindex="-1">AI 协作资产全景图 <a class="header-anchor" href="#ai-协作资产全景图" aria-label="Permalink to &quot;AI 协作资产全景图&quot;">​</a></h2><p>一项任务完成后，值得保留的内容不只有最终文件。长期使用 WorkBuddy 时，应同时管理工作成果、协作方法和接续能力，让资产在更换人员、设备或 Agent 后仍然可用。</p><table tabindex="0"><thead><tr><th>资产类别</th><th>保存什么</th><th>典型内容</th><th>治理目标</th></tr></thead><tbody><tr><td>成果资产</td><td>已经完成并通过验收的工作结果</td><td>文档、表格、代码、图片、项目数据和发布记录</td><td>来源清楚、版本可辨、权限明确、能够交接</td></tr><tr><td>协作资产</td><td>让人和 Agent 按同一方法继续工作的上下文</td><td>任务边界、协作规则、模板、Skill、已确认决策和长期记忆</td><td>经过确认、按需读取、可维护、可迁移</td></tr><tr><td>连续性资产</td><td>让前两类资产在故障或更换环境后恢复使用的保障</td><td>源文件、历史版本、独立快照、校验清单、恢复说明和演练记录</td><td>有多个时间点、可校验、能恢复、恢复过程有记录</td></tr></tbody></table>',5)),l(a,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E4%BB%BB%E5%8A%A1%E7%9B%AE%E6%A0%87%E4%B8%8E%E6%8E%88%E6%9D%83%E8%B5%84%E6%96%99%5D%20--%3E%20B%5B%E6%88%90%E6%9E%9C%E8%B5%84%E4%BA%A7%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%A4%8D%E7%9B%98%E4%B8%8E%E8%B4%A3%E4%BB%BB%E4%BA%BA%E7%A1%AE%E8%AE%A4%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%8D%8F%E4%BD%9C%E8%B5%84%E4%BA%A7%5D%0A%20%20%20%20B%20--%3E%20E%5B%E8%BF%9E%E7%BB%AD%E6%80%A7%E8%B5%84%E4%BA%A7%5D%0A%20%20%20%20D%20--%3E%20E%0A%20%20%20%20E%20--%3E%20F%5B%E6%8D%A2%E4%BA%BA%E3%80%81%E6%8D%A2%E8%AE%BE%E5%A4%87%E6%88%96%E6%8D%A2%20Agent%20%E5%90%8E%E7%BB%A7%E7%BB%AD%E5%B7%A5%E4%BD%9C%5D%0A"}),t[1]||(t[1]=e('<p>三类资产需要分别治理：成果资产保留原件、版本和验收记录；协作资产只沉淀稳定且会复用的方法和背景；连续性资产通过独立快照、校验与恢复演练证明可用。聊天流水、临时要求和未经确认的推断不直接进入长期协作资产。</p><p>本篇重点讲协作资产如何逐步变成方法卡、Skill、多 Agent 分工和可靠自动化。相关成果仍按第 12、16、20 章管理来源与版本，备份、校验与恢复演练方法见第 24 章。</p><h2 id="子页面" tabindex="-1">子页面 <a class="header-anchor" href="#子页面" aria-label="Permalink to &quot;子页面&quot;">​</a></h2><ul><li><a href="./第 22 章 Vibe Coding：从想法到产品上线/">第 22 章 Vibe Coding：从想法到上线</a></li><li><a href="./第 23 章 打造skill：将书和视频蒸馏为可执行 Skill/">第 23 章 把模板、规范与步骤制作成 Skill</a></li><li><a href="./第 24 章 其他用法补充：WorkBuddy 实操案例集/">第 24 章 备份、校验与恢复演练</a></li><li><a href="./第 25 章 如何进行多 Agent 系统设计/">第 25 章 多 Agent 分工、汇总与复核</a></li><li><a href="./第 26 章 自动化工作流的可靠性/">第 26 章 可靠自动化：预检、确认、日志与回退</a></li></ul>',4))])}const b=E(A,[["render",o]]);export{D as __pageData,b as default};
